/** Glossary data for the /knowledge hub — 100+ terms grouped by first Hebrew letter. */

export type GlossaryTerm = {
  slug: string;
  term: string;
  letter: string;
  definition: string;
  related: string[];
  href?: string;
};

/** A short, one-line teaser derived from a term's full definition (first
 *  sentence, capped) — used on cards where only a preview line is shown. */
export function glossaryShort(definition: string, max = 120): string {
  const firstSentence = definition.split(/(?<=[.!?])\s/)[0] ?? definition;
  const base = firstSentence.length <= max ? firstSentence : definition;
  if (base.length <= max) return base.trim();
  const cut = base.slice(0, max);
  const lastSpace = cut.lastIndexOf(" ");
  return `${cut.slice(0, lastSpace > 60 ? lastSpace : max).trim()}…`;
}

/** All glossary slugs — feeds generateStaticParams for the term pages. */
export const glossaryTermSlugs = (): string[] =>
  GLOSSARY_TERMS.map((t) => t.slug);

/** Resolve a single glossary term by slug, or undefined. */
export const getGlossaryTerm = (slug: string): GlossaryTerm | undefined =>
  GLOSSARY_TERMS.find((t) => t.slug === slug);

